import React, { useState } from "react";

const fontLink = document.createElement("link");
fontLink.rel = "stylesheet";
fontLink.href = "https://fonts.googleapis.com/css2?family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400&display=swap";
document.head.appendChild(fontLink);
// Ensure proper mobile viewport (prevents unwanted scaling)
if (!document.querySelector('meta[name="viewport"]')) {
  const meta = document.createElement('meta');
  meta.name = 'viewport';
  meta.content = 'width=device-width, initial-scale=1, viewport-fit=cover';
  document.head.appendChild(meta);
}

const FONT = "'DM Sans', -apple-system, sans-serif";
const OVE_PHOTO = "data:image/png;base64,";

const FIELDS = [
  { key: "bio",          label: "About me",           placeholder: "Write something about yourself...",      multiline: true  },
  { key: "hobbies",      label: "Hobbies",             placeholder: "What do you enjoy?",                    multiline: false },
  { key: "dealBreaker",  label: "Deal breaker",        placeholder: "What's a hard no for you?",             multiline: false },
  { key: "idealPartner", label: "Ideal partner",       placeholder: "Describe your ideal match...",          multiline: false },
  { key: "idealSunday",  label: "Ideal Sunday",        placeholder: "How do you spend a perfect Sunday?",    multiline: false },
  { key: "twoTruths",    label: "Two truths & a lie",  placeholder: "List all three, separated by commas.",  multiline: false },
  { key: "profileMakers", label: "My profile makers",   placeholder: "Who filled this in?",                       multiline: false },
];

const C = {
  teal:      "#65aab6",
  tealDark:  "#4a8a96",
  tealLight: "#e8f5f7",
  tealMid:   "#b2d8de",
  bg:        "#f0f9fa",
  white:     "#ffffff",
  ink:       "#1a1a1a",
  muted:     "#6b7280",
  border:    "#e5e7eb",
  pill:      "#e8f5f7",
  pillText:  "#4a8a96",
};

export default function App() {
  const [phase, setPhase] = useState("form");
  const [form, setForm] = useState({
    bio: "", hobbies: "", dealBreaker: "",
    idealPartner: "", idealSunday: "", twoTruths: "", profileMakers: "",
  });
  const [focused, setFocused] = useState(null);

  function set(k, v) { setForm(p => ({...p, [k]: v})); }

  // ── FORM ──────────────────────────────────────────────────────────────────
  if (phase === "form") return (
    <div style={{
      minHeight: "100dvh", background: C.bg,
      fontFamily: FONT, display: "flex",
      flexDirection: "column", alignItems: "center",
      padding: "0 0 220px", textAlign: "left",
    }}>
      {/* Top bar */}
      <div style={{
        width: "100%", background: C.white,
        borderBottom: `1px solid ${C.border}`,
        padding: "16px 20px", display: "flex",
        alignItems: "center", justifyContent: "center",
        position: "sticky", top: 0, zIndex: 10,
        boxSizing: "border-box",
      }}>
        <div style={{fontSize: 11, fontWeight: 700, color: C.teal, letterSpacing: "0.18em", textTransform: "lowercase"}}>
          residents' matchmaking association
        </div>
      </div>

      <div style={{maxWidth: 480, width: "100%", padding: "24px 16px 0", boxSizing: "border-box"}}>

        {/* Photo card */}
        <div style={{
          borderRadius: 20, overflow: "hidden",
          boxShadow: "0 2px 20px rgba(0,0,0,0.10)",
          marginBottom: 20, position: "relative",
          background: C.white,
        }}>
          <img
            src={OVE_PHOTO} alt="Ove"
            style={{width: "100%", display: "block", height: 280, objectFit: "cover", objectPosition: "center top"}}
          />
          <div style={{
            position: "absolute", bottom: 0, left: 0, right: 0,
            background: "linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 100%)",
            padding: "40px 20px 18px",
          }}>
            <div style={{display: "flex", alignItems: "flex-end", justifyContent: "space-between"}}>
              <div>
                <div style={{fontSize: 28, fontWeight: 700, color: C.white, lineHeight: 1.1}}>
                  Ove, <span style={{fontWeight: 300}}>59</span>
                </div>
                <div style={{fontSize: 14, color: "rgba(255,255,255,0.8)", marginTop: 3, fontWeight: 400}}>
                  Involuntary retiree
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Instruction */}
        <div style={{
          fontSize: 13, color: C.muted, marginBottom: 20,
          textAlign: "center", lineHeight: 1.5,
        }}>
          Answer as Ove would. Keep it brief. He wouldn't bother otherwise.
        </div>

        {/* Fields */}
        <div style={{display: "flex", flexDirection: "column", gap: 12}}>
          {FIELDS.map(({ key, label, placeholder, multiline }) => (
            <div key={key} style={{
              background: C.white, borderRadius: 16,
              border: `1.5px solid ${focused === key ? C.teal : C.border}`,
              padding: "14px 16px",
              transition: "border-color 0.15s",
              boxShadow: focused === key ? `0 0 0 3px ${C.tealLight}` : "0 1px 4px rgba(0,0,0,0.04)",
            }}>
              <div style={{
                fontSize: 11, fontWeight: 600, color: C.teal,
                textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 6,
              }}>{label}</div>
              {multiline ? (
                <textarea
                  value={form[key]}
                  onChange={e => set(key, e.target.value)}
                  onFocus={(e) => { setFocused(key); setTimeout(() => e.target.scrollIntoView({behavior:"smooth",block:"center"}), 150); }}
                  onBlur={() => setFocused(null)}
                  placeholder={placeholder}
                  rows={3}
                  style={{
                    width: "100%", border: "none", outline: "none",
                    fontFamily: FONT, fontSize: 16, color: C.ink,
                    background: "transparent", resize: "none",
                    lineHeight: 1.5, boxSizing: "border-box",
                    "::placeholder": {color: "#9ca3af"},
                  }}
                />
              ) : (
                <input
                  type="text"
                  value={form[key]}
                  onChange={e => set(key, e.target.value)}
                  onFocus={(e) => { setFocused(key); setTimeout(() => e.target.scrollIntoView({behavior:"smooth",block:"center"}), 150); }}
                  onBlur={() => setFocused(null)}
                  placeholder={placeholder}
                  style={{
                    width: "100%", border: "none", outline: "none",
                    fontFamily: FONT, fontSize: 16, color: C.ink,
                    background: "transparent", boxSizing: "border-box",
                  }}
                />
              )}
            </div>
          ))}
        </div>

        {/* Submit */}
        <button
          onClick={() => { setPhase("card"); window.scrollTo({top:0,behavior:"smooth"}); }}
          style={{
            width: "100%", marginTop: 24, padding: "16px",
            background: C.teal, color: C.white, border: "none",
            borderRadius: 50, fontFamily: FONT, fontSize: 16,
            fontWeight: 700, cursor: "pointer", letterSpacing: "-0.2px",
            boxShadow: `0 4px 14px rgba(101,170,182,0.4)`,
          }}
        >
          See Profile →
        </button>
      </div>
    </div>
  );

  // ── PROFILE CARD ──────────────────────────────────────────────────────────
  return (
    <div style={{
      minHeight: "100dvh", background: C.bg,
      fontFamily: FONT, display: "flex",
      flexDirection: "column", alignItems: "center",
      padding: "0 0 80px", textAlign: "left",
    }}>
      {/* Top bar */}
      <div style={{
        width: "100%", background: C.white,
        borderBottom: `1px solid ${C.border}`,
        padding: "16px 20px",
        display: "flex", alignItems: "center", justifyContent: "space-between",
        position: "sticky", top: 0, zIndex: 10,
        boxSizing: "border-box",
      }}>
        <button onClick={() => setPhase("form")} style={{
          background: "none", border: "none", fontSize: 15,
          color: C.teal, cursor: "pointer", fontFamily: FONT,
          fontWeight: 600, padding: 0,
        }}>← Edit</button>
        <div style={{fontSize: 11, fontWeight: 700, color: C.teal, letterSpacing: "0.18em", textTransform: "lowercase"}}>
          residents' matchmaking association
        </div>
        <div style={{width: 48}} />
      </div>

      <div style={{maxWidth: 480, width: "100%", padding: "0 0 20px", boxSizing: "border-box"}}>

        {/* Main photo */}
        <div style={{position: "relative", marginBottom: 0}}>
          <img
            src={OVE_PHOTO} alt="Ove"
            style={{width: "100%", display: "block", height: 420, objectFit: "cover", objectPosition: "center top"}}
          />
          {/* Like / Nope buttons */}
          <div style={{
            position: "absolute", bottom: 20, left: 0, right: 0,
            display: "flex", justifyContent: "center", gap: 20,
          }}>
            <div style={{
              width: 56, height: 56, borderRadius: "50%",
              background: C.white, display: "flex", alignItems: "center",
              justifyContent: "center", fontSize: 24,
              boxShadow: "0 4px 14px rgba(0,0,0,0.15)",
            }}>✕</div>
            <div style={{
              width: 70, height: 70, borderRadius: "50%",
              background: C.teal, display: "flex", alignItems: "center",
              justifyContent: "center", fontSize: 28, color: C.white,
              boxShadow: `0 4px 18px rgba(101,170,182,0.5)`,
              marginTop: -7,
            }}>♥</div>
            <div style={{
              width: 56, height: 56, borderRadius: "50%",
              background: C.white, display: "flex", alignItems: "center",
              justifyContent: "center", fontSize: 22,
              boxShadow: "0 4px 14px rgba(0,0,0,0.15)",
            }}>⭐</div>
          </div>
        </div>

        {/* Info card */}
        <div style={{background: C.white, padding: "22px 20px 8px"}}>
          <div style={{fontSize: 30, fontWeight: 700, color: C.ink, letterSpacing: "-0.5px"}}>
            Ove, <span style={{fontWeight: 300, color: C.muted}}>59</span>
          </div>
          <div style={{fontSize: 14, color: C.muted, marginTop: 2, marginBottom: 16}}>
            Involuntary retiree
          </div>

          {/* Stat pills */}
          <div style={{display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 4}}>
            {[
              {icon: "📏", text: "5'10\""},
              {icon: "🚗", text: "Drives a SAAB"},
              {icon: "🐱", text: "Has a cat"},
              {icon: "🚭", text: "Non-smoker"},
            ].map(({ icon, text }) => (
              <div key={text} style={{
                background: C.pill, borderRadius: 50,
                padding: "6px 14px", fontSize: 13,
                color: C.pillText, fontWeight: 500,
                display: "flex", alignItems: "center", gap: 6,
              }}>
                <span>{icon}</span><span>{text}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Divider */}
        <div style={{height: 8, background: C.bg}} />

        {/* Profile sections */}
        <div style={{background: C.white, padding: "6px 0"}}>
          {FIELDS.map(({ key, label }) => form[key] ? (
            <div key={key} style={{padding: "16px 20px", borderBottom: `1px solid ${C.border}`}}>
              <div style={{
                fontSize: 11, fontWeight: 600, color: C.teal,
                textTransform: "uppercase", letterSpacing: "0.08em", marginBottom: 6,
              }}>{label}</div>
              <div style={{fontSize: 15, color: C.ink, lineHeight: 1.6}}>
                {form[key]}
              </div>
            </div>
          ) : null)}
        </div>

        {/* Bottom padding */}
        <div style={{height: 8, background: C.bg}} />

        {/* Footer tag */}
        <div style={{
          background: C.white, padding: "16px 20px",
          display: "flex", justifyContent: "center",
        }}>
          <div style={{
            fontSize: 12, color: C.muted, fontStyle: "italic",
            textAlign: "center", lineHeight: 1.6,
          }}>
            "I am not a violent man. But I have limits."
          </div>
        </div>

      </div>
    </div>
  );
}
